import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { CreditCard, Users, AlertTriangle, TrendingUp, Calendar } from 'lucide-react';

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalMes: 0,
    parcelasFuturas: 0,
    maiorGasto: 0,
    totalGeral: 0,
    qtdResponsavel: {}
  });

  const mesAtual = new Date().getMonth();
  const anoAtual = new Date().getFullYear();

  useEffect(() => {
    async function carregarIndicadores() {
      const { data } = await supabase.from('compras').select('*');
      
      if (data) {
        let totalMes = 0;
        let parcelasFuturas = 0;
        let maiorGasto = 0;
        let totalGeral = 0;
        let responsaveis = {};

        data.forEach(item => {
          const valorTotal = parseFloat(item.valor_total);
          const numParcelas = item.num_parcelas || 1;
          const valorParcela = valorTotal / numParcelas;
          totalGeral += valorTotal;

          const resp = item.responsavel || 'Indefinido';
          responsaveis[resp] = (responsaveis[resp] || 0) + valorTotal;

          for (let i = 0; i < numParcelas; i++) {
            const dataParcela = new Date(new Date(item.data_compra).getFullYear(), new Date(item.data_compra).getMonth() + i, 1);
            
            if (dataParcela.getMonth() === mesAtual && dataParcela.getFullYear() === anoAtual) {
              totalMes += valorParcela;
              if (valorParcela > maiorGasto) maiorGasto = valorParcela;
            }

            if (dataParcela > new Date()) {
              parcelasFuturas++;
            }
          }
        });

        setStats({ totalMes, parcelasFuturas, maiorGasto, totalGeral, qtdResponsavel: responsaveis });
      }
    }
    carregarIndicadores();
  }, [mesAtual, anoAtual]);

  return (
    <div className="fade-in">
      <h2 style={{ marginBottom: '30px' }}>Visão Estratégica</h2>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '24px' }}>
        
        <div className="card" style={{ borderTop: '4px solid var(--primary)' }}>
          <div style={headerCard}><Calendar size={18} /> GASTOS DESTE MÊS</div>
          <h1 style={valueStyle}>R$ {stats.totalMes.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</h1>
          <p style={subValue}>Total comprometido para o mês atual</p>
        </div>

        <div className="card" style={{ borderTop: '4px solid #f59e0b' }}>
          <div style={headerCard}><CreditCard size={18} /> PARCELAS EM ABERTO</div>
          <h1 style={valueStyle}>{stats.parcelasFuturas} <small style={{fontSize: '0.9rem'}}>unid.</small></h1>
          <p style={subValue}>Parcelas que vencem nos meses futuros</p>
        </div>

        <div className="card" style={{ borderTop: '4px solid var(--danger)' }}>
          <div style={headerCard}><AlertTriangle size={18} /> MAIOR PARCELA ATUAL</div>
          <h1 style={valueStyle}>R$ {stats.maiorGasto.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</h1>
          <p style={subValue}>O maior valor individual deste mês</p>
        </div>

        <div className="card" style={{ borderTop: '4px solid var(--success)' }}>
          <div style={headerCard}><Users size={18} /> GASTO TOTAL POR PESSOA</div>
          <div style={{ marginTop: '20px' }}>
            {Object.keys(stats.qtdResponsavel).map(r => (
              <div key={r} style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px', fontSize: '0.95rem' }}>
                <span style={{ fontWeight: '500' }}>{r}:</span>
                <span style={{ fontWeight: '700' }}>R$ {stats.qtdResponsavel[r].toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</span>
              </div>
            ))}
          </div>
        </div>

      </div>

      <div className="card" style={{ marginTop: '24px', background: 'linear-gradient(135deg, var(--primary) 0%, var(--secondary) 100%)', color: 'white' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
          <div style={{ background: 'rgba(255,255,255,0.2)', padding: '15px', borderRadius: '15px' }}><TrendingUp size={32} /></div>
          <div>
            <span style={{ opacity: 0.8, fontSize: '0.9rem', fontWeight: '500' }}>Volume Total Historicamente Lançado</span>
            <h2 style={{ margin: 0, fontSize: '2rem' }}>R$ {stats.totalGeral.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}</h2>
          </div>
        </div>
      </div>
    </div>
  );
};

const headerCard = { display: 'flex', alignItems: 'center', gap: '10px', color: 'var(--text-muted)', fontSize: '0.75rem', fontWeight: '700', letterSpacing: '0.05em' };
const valueStyle = { fontSize: '2.4rem', margin: '18px 0 6px 0', color: 'var(--text-main)', letterSpacing: '-1.5px', fontWeight: '700' };
const subValue = { fontSize: '0.85rem', color: 'var(--text-muted)', margin: 0 };

export default Dashboard;
